<?php namespace App\Models; use App\Enums\MaintenanceStatus;use Illuminate\Database\Eloquent\Factories\HasFactory;use Illuminate\Database\Eloquent\Model;use Illuminate\Database\Eloquent\Relations\BelongsTo; class PreventiveMaintenance extends Model{use HasFactory; protected $fillable=['asset_id','frequency','last_maintenance','next_maintenance','technician_id','status']; protected function casts():array{return ['last_maintenance'=>'date','next_maintenance'=>'date','status'=>MaintenanceStatus::class];} public function asset():BelongsTo{return $this->belongsTo(Asset::class);} public function technician():BelongsTo{return $this->belongsTo(User::class,'technician_id');}}
